### Custom Code Field Block with Language Picker Config

Source: https://github.com/payloadcms/payload/blob/main/docs/rich-text/custom-features.mdx

This TypeScript configuration defines a rich text field using Payload CMS's BlocksFeature. It includes a custom 'Code' block with a 'language' select field and a 'code' type field that references a custom component for rendering. Dependencies include `@payloadcms/richtext-lexical` and `@payloadcms/ui`.

```typescript
import {
  BlocksFeature,
  lexicalEditor,
} from '@payloadcms/richtext-lexical'

export const languages = {
  ts: 'TypeScript',
  plaintext: 'Plain Text',
  tsx: 'TSX',
  js: 'JavaScript',
  jsx: 'JSX',
}

// ...
{
  name: 'richText',
  type: 'richText',
  editor: lexicalEditor({
    features: ({ defaultFeatures }) => [
      ...defaultFeatures,
      BlocksFeature({
        blocks: [
          {
            slug: 'Code',
            fields: [
              {
                type: 'select',
                name: 'language',
                options: Object.entries(languages).map(([key, value]) => ({
                  label: value,
                  value: key,
                })),
                defaultValue: 'ts',
              },
              {
                admin: {
                  components: {
                    Field: './path/to/CodeComponent#Code',
                  },
                },
                name: 'code',
                type: 'code',
              },
            ],
          }
        ],
        inlineBlocks: [],
      }),
    ],
  }),
}
```

