### Define QuoteBlock and Collection with Blocks Field in Payload CMS using TypeScript

Source: https://github.com/payloadcms/payload/blob/main/docs/fields/blocks.mdx

Complete example of defining a QuoteBlock with slug, image metadata, interface name, and text fields, then implementing it in a collection configuration with a blocks field. This demonstrates how to create reusable block types with validation constraints (minRows, maxRows) for structured content management in Payload CMS.

```ts
import { Block, CollectionConfig } from 'payload'

const QuoteBlock: Block = {
  slug: 'Quote', // required
  imageURL: 'https://google.com/path/to/image.jpg',
  imageAltText: 'A nice thumbnail image to show what this block looks like',
  interfaceName: 'QuoteBlock', // optional
  fields: [
    // required
    {
      name: 'quoteHeader',
      type: 'text',
      required: true,
    },
    {
      name: 'quoteText',
      type: 'text',
    },
  ],
}

export const ExampleCollection: CollectionConfig = {
  slug: 'example-collection',
  fields: [
    {
      name: 'layout', // required
      type: 'blocks', // required
      minRows: 1,
      maxRows: 20,
      blocks: [
        // required
        QuoteBlock,
      ],
    },
  ],
}
```

